sql:
SELECT new_confirmed_cases
FROM specimen_collections
WHERE specimen_collection_date = '2020-03-14';

external_knowledge:
External knowledge: 
; The term 'most recent specimen collections' refers to the collections made on the latest date; 
; 'highest cumulative cases' refers to the maximum total number of cases reported by the collection date, in descending order.

sql:
SELECT specimen_collection_date, new_confirmed_cases
FROM specimen_collections
ORDER BY specimen_collection_date DESC;

SELECT cumulative_confirmed_cases
FROM specimen_collections
WHERE disease_id = 1 AND specimen_collection_date = '2020-03-14';

SELECT specimen_collection_date
FROM specimen_collections
ORDER BY specimen_collection_date DESC;

SELECT specimen_collection_date, new_confirmed_cases, cumulative_confirmed_cases
FROM specimen_collections
ORDER BY specimen_collection_date;

SELECT collection_id, MAX(last_updated) AS latest_update
FROM specimen_collections
GROUP BY collection_id;

SELECT DISTINCT race_ethnicity
FROM demographics
ORDER BY race_ethnicity;

SELECT DISTINCT d.race_ethnicity
FROM demographics d
INNER JOIN demographic_cases dc ON d.demographic_id = dc.demographic_id;
